-- create "carts" table
CREATE TABLE "carts" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "status" smallint NOT NULL DEFAULT 0, "currency" character varying(3) NOT NULL, "shop_id" bigint NOT NULL, "member_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "carts_members_member" FOREIGN KEY ("member_id") REFERENCES "members" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "carts_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "carts_status_check" CHECK (status = ANY (ARRAY[0, 1, 2])));
-- create index "cart_member_id" to table: "carts"
CREATE INDEX "cart_member_id" ON "carts" ("member_id");
-- create index "carts_one_active_per_member" to table: "carts"
CREATE UNIQUE INDEX "carts_one_active_per_member" ON "carts" ("shop_id", "member_id") WHERE (status = 0);
-- create "cart_items" table
CREATE TABLE "cart_items" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "quantity" integer NOT NULL, "price_amount" bigint NOT NULL, "currency" character varying(3) NOT NULL, "cart_id" bigint NOT NULL, "shop_id" bigint NOT NULL, "sku_id" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "cart_items_carts_items" FOREIGN KEY ("cart_id") REFERENCES "carts" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "cart_items_product_skus_sku" FOREIGN KEY ("sku_id") REFERENCES "product_skus" ("id") ON UPDATE NO ACTION ON DELETE SET NULL, CONSTRAINT "cart_items_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "cart_items_price_amount_check" CHECK (price_amount >= 0), CONSTRAINT "cart_items_quantity_check" CHECK (quantity > 0));
-- create index "cartitem_cart_id" to table: "cart_items"
CREATE INDEX "cartitem_cart_id" ON "cart_items" ("cart_id");
-- create index "cartitem_sku_id" to table: "cart_items"
CREATE INDEX "cartitem_sku_id" ON "cart_items" ("sku_id");
